body:
### Version

Yosys 0.57+148

### On which OS did this happen?

Linux

### Reproduction Steps

This is my code (similar to #5366 as this bug was met when trying to debug the other issue)
```sv
read_verilog -sv << EOF
interface simple_if;
    logic data;
    modport driver(output data);
    modport receiver(input data);
endinterface

module driver_mod(simple_if.driver intf, input logic in);
    assign intf.data = in;
endmodule

module receiver_mod(simple_if.receiver intf, output logic out);
    assign out = intf.data;
endmodule

module simple_interface_test;
    logic [1:0] inputs;
    logic [1:0] outputs;

    // Hardcode input values - test case that should expose the bug
    assign inputs = 2'b10; // inputs[1]=1, inputs[0]=0

    // Use individual interfaces instead of an array
    simple_if intf0();
    simple_if intf1();

    driver_mod d0(.intf(intf0), .in(inputs[0]));
    driver_mod d1(.intf(intf1), .in(inputs[1]));

    receiver_mod r0(.intf(intf0), .out(outputs[0]));
    receiver_mod r1(.intf(intf1), .out(outputs[1]));

    // Assert expected results - outputs should match inputs
    always_comb assert(outputs[0] == 1'b0); // inputs[0] = 0, so outputs[0] should be 0
    always_comb assert(outputs[1] == 1'b1); // inputs[1] = 1, so outputs[1] should be 1
    always_comb assert(outputs == 2'b10);   // Overall: outputs should equal inputs (2'b10)
endmodule
EOF

write_cxxrtl simple_interface_test.cc
```

and this is my testbench
```cpp
#include "simple_interface_test.cc"

#include <fstream>
#include <iostream>
#include <iomanip>
#include <cstdint>
#include <string>
#include <sstream>
#include <type_traits>
#include <bitset>

// Template helpers to detect and work with both value<> and wire<> types
template<typename T>
struct has_curr {
    template<typename U>
    static auto test(int) -> decltype(std::declval<U>().curr, std::true_type{});
    template<typename>
    static std::false_type test(...);
    using type = decltype(test<T>(0));
    static constexpr bool value = type::value;
};

// Helper function to get port value - works with both value<> and wire<>
template<typename T, typename PortType>
typename std::enable_if<has_curr<PortType>::value, T>::type
_get_port_value(const PortType& port) {
    return port.curr.template get<T>();
}

template<typename T, typename PortType>
typename std::enable_if<!has_curr<PortType>::value, T>::type
_get_port_value(const PortType& port) {
    return port.template get<T>();
}

// Helper function to get port bit - works with both value<> and wire<>
template<typename PortType>
typename std::enable_if<has_curr<PortType>::value, bool>::type
_get_port_value(const PortType& port, int bit) {
    return port.curr.bit(bit);
}

template<typename PortType>
typename std::enable_if<!has_curr<PortType>::value, bool>::type
_get_port_value(const PortType& port, int bit) {
    return port.bit(bit);
}

// Helper function to get wide port value - works with both value<> and wire<>
template<typename PortType>
auto _get_port_value_wide(const PortType& port) -> typename std::enable_if<has_curr<PortType>::value, decltype(port.curr)>::type {
    return port.curr;
}

template<typename PortType>
auto _get_port_value_wide(const PortType& port) -> typename std::enable_if<!has_curr<PortType>::value, PortType>::type {
    return port;
}

int main(int argc, char** argv) {
    cxxrtl_design::p_simple__interface__test dut; // DUT instance

    std::cout << "CXXRTL Simulation for simple_interface_test:" << std::endl;
    std::cout << "This module has hardcoded inputs = 2'b10 and should produce outputs = 2'b10" << std::endl;
    std::cout << std::endl;

    // No external inputs to apply - the module has hardcoded inputs
    // inputs[1] = 1, inputs[0] = 0 (i.e., inputs = 2'b10)

    // Run combinational logic to settle
    std::cout << "Running simulation steps to settle combinational logic..." << std::endl;
    for (int settle_step = 0; settle_step < 20; settle_step++) {
        dut.step();
    }

    // Also call debug_eval to ensure all connections are evaluated
    // dut.debug_eval(); // <-------------------------UNCOMMENT THIS LINE

    // Read outputs from DUT
    uint32_t outputs = _get_port_value<uint32_t>(dut.p_outputs);

    // Extract individual bits
    bool output_0 = (outputs & 1);
    bool output_1 = ((outputs >> 1) & 1);

    // Print results
    std::cout << "Simulation Results:" << std::endl;
    std::cout << "Expected: inputs = 2'b10 -> outputs = 2'b10" << std::endl;
    std::cout << "Actual results:" << std::endl;
    std::cout << "  outputs = 0b" << std::bitset<2>(outputs) << " (" << outputs << ")" << std::endl;
    std::cout << "  outputs[1] = " << output_1 << " (expected: 1)" << std::endl;
    std::cout << "  outputs[0] = " << output_0 << " (expected: 0)" << std::endl;
    std::cout << std::endl;

    // Verify expectations
    bool test_passed = true;
    if (output_0 != 0) {
        std::cout << "ERROR: outputs[0] = " << output_0 << ", expected 0" << std::endl;
        test_passed = false;
    }
    if (output_1 != 1) {
        std::cout << "ERROR: outputs[1] = " << output_1 << ", expected 1" << std::endl;
        test_passed = false;
    }
    if (outputs != 2) {
        std::cout << "ERROR: outputs = " << outputs << ", expected 2 (0b10)" << std::endl;
        test_passed = false;
    }

    if (test_passed) {
        std::cout << "✓ TEST PASSED: All outputs match expected values" << std::endl;
        std::cout << "Interface connections working correctly through individual interfaces" << std::endl;
    } else {
        std::cout << "✗ TEST FAILED: Output mismatch detected" << std::endl;
        std::cout << "This indicates a bug in Yosys interface handling" << std::endl;
    }

    return test_passed ? 0 : 1;
}
```

Then I run 
```sh
yosys test.ys
g++ -std=c++17 -O0 -I$(yosys-config --datdir)/include/backends/cxxrtl/runtime testbench.cpp -I. -o sim && ./sim
```

If I uncomment the `debug_eval` then the code evaluates correctly. 

It seems to me as if cxxrtl is incorrectly placing the interface connections in the debug_eval rather than in the eval

### Expected Behavior



I should get 
```txt
Actual results:
  outputs = 0b10 (2)
  outputs[1] = 1 (expected: 1)
  outputs[0] = 0 (expected: 0)
```

### Actual Behavior

Instead I get 

```txt
Actual results:
  outputs = 0b00 (0)
  outputs[1] = 0 (expected: 1)
  outputs[0] = 0 (expected: 0)
```

